@namespace Lumeo
@inject IComponentInteropService Interop

@{
    var visibleItems = VisibleItems;
    // The highlight is anchored to an item identity (_highlighted), not a raw
    // ordinal, so inserting/removing an item above it doesn't slide the
    // highlight (and Enter) onto a different command (#214 follow-up). It only
    // surfaces while the anchored item is still visible under the current filter.
    var highlighted = _highlighted is not null && visibleItems.Contains(_highlighted)
        ? _highlighted
        : null;
    var context = new CommandContext(
        SearchText,
        EventCallback.Factory.Create<string>(this, OnSearchChanged),
        EventCallback.Factory.Create<KeyboardEventArgs>(this, OnNavigationKey),
        visibleItems.Count,
        _listId,
        highlighted?.ItemId,
        this);
}

<div class="@CssClass" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string SearchText { get; set; } = "";
    private readonly string _listId = LumeoIds.New("cmd-list");

    // Items register once per mounted instance — idempotent and keyed on the
    // component itself (OnParametersSet can run twice per parent render via
    // cascading-value double notification) — and unregister only on Dispose.
    // The filter is applied at read time (VisibleItems) instead of churning
    // register/unregister on visibility, so the keyboard-nav list keeps DOM
    // order even after a filter hides and re-shows items.
    private readonly List<CommandItem> _items = new();

    // The highlighted item, anchored by identity rather than by ordinal so the
    // highlight (and Enter target) follows the SAME command when items register,
    // unregister or reorder around it. null = nothing highlighted (pristine
    // palette). The visible index is derived on demand from this.
    private CommandItem? _highlighted;

    // Last item id we scrolled into view. Tracked so OnAfterRenderAsync only
    // issues a scroll when the highlight actually moves to a different item
    // (#214) — not on every unrelated re-render.
    private string? _lastScrolledItemId;

    private string CssClass => Cx.Merge("flex h-full w-full flex-col overflow-hidden rounded-md bg-popover text-popover-foreground", Class);

    /// <summary>
    /// The filter shared by Command (nav list + visible count), CommandItem
    /// (self-hide) and CommandGroup (hide-when-empty). An item with no
    /// FilterValue always matches. Matching is now smarter than a plain
    /// substring (#214): a contiguous substring match still wins, but the term
    /// also matches when its characters appear in order anywhere in the filter
    /// value (subsequence) — so "gp" finds "Git Push" and "stng" finds
    /// "Settings". This mirrors cmdk's forgiving fuzzy search while keeping the
    /// trivial substring case (the common one) cheap and first.
    /// </summary>
    internal static bool MatchesFilter(string searchText, string? filterValue)
    {
        if (string.IsNullOrEmpty(searchText) || string.IsNullOrEmpty(filterValue))
            return true;
        if (filterValue.Contains(searchText, StringComparison.OrdinalIgnoreCase))
            return true;
        return IsSubsequence(searchText, filterValue);
    }

    /// <summary>True when every non-whitespace character of <paramref name="needle"/>
    /// appears in <paramref name="haystack"/> in the same order (case-insensitive).
    /// Spaces in the needle are ignored so a multi-word query ("git push")
    /// matches "Git: Push to remote". Returns false for an all-whitespace needle
    /// so a stray space never widens results to everything.</summary>
    private static bool IsSubsequence(string needle, string haystack)
    {
        var n = 0;
        // Skip leading whitespace; if the needle is all whitespace, no match.
        while (n < needle.Length && char.IsWhiteSpace(needle[n])) n++;
        if (n >= needle.Length) return false;

        for (var h = 0; h < haystack.Length && n < needle.Length; h++)
        {
            if (char.IsWhiteSpace(needle[n])) { n++; continue; }
            if (char.ToLowerInvariant(haystack[h]) == char.ToLowerInvariant(needle[n]))
                n++;
        }
        // Consume any trailing whitespace in the needle.
        while (n < needle.Length && char.IsWhiteSpace(needle[n])) n++;
        return n == needle.Length;
    }

    /// <summary>Registered items that pass the current filter, in DOM order.</summary>
    private List<CommandItem> VisibleItems
        => _items.Where(i => MatchesFilter(SearchText, i.ItemFilterValue)).ToList();

    internal void RegisterItem(CommandItem item)
    {
        if (_items.Contains(item)) return;
        _items.Add(item);
        StateHasChanged();
    }

    internal void UnregisterItem(CommandItem item)
    {
        if (!_items.Remove(item)) return;
        // The highlighted command itself was removed (it shrank away, or the
        // list emptied for a refill). Drop the anchor so a refill starts from a
        // clean 'pristine' state instead of resurrecting a stale ordinal — the
        // next ArrowDown/ArrowUp seeds the highlight from the edge.
        if (ReferenceEquals(item, _highlighted))
            _highlighted = null;
        StateHasChanged();
    }

    /// <summary>
    /// A registered item's FilterValue/Disabled parameter changed after
    /// registration — re-render so the visible count, group hiding and the
    /// highlight's disabled skip-list pick up the new values.
    /// </summary>
    internal void NotifyItemChanged() => StateHasChanged();

    private Task OnSearchChanged(string text)
    {
        SearchText = text;
        // cmdk resets the highlight to the first selectable result on every
        // filter change so Enter always acts on the top of what the user sees.
        // This is the ONLY place that deliberately re-seeds the highlight.
        _highlighted = VisibleItems.FirstOrDefault(i => !i.IsDisabled);
        StateHasChanged();
        return Task.CompletedTask;
    }

    // Keyboard navigation driven from the CommandInput while it keeps focus
    // (WAI-ARIA combobox-listbox pattern: the input only moves
    // aria-activedescendant, never DOM focus).
    private async Task OnNavigationKey(KeyboardEventArgs e)
    {
        if (e.IsComposing) return; // IME candidate navigation owns these keys

        switch (e.Key)
        {
            case "ArrowDown":
                MoveHighlight(1);
                break;
            case "ArrowUp":
                MoveHighlight(-1);
                break;
            case "Home":
                _highlighted = VisibleItems.FirstOrDefault(i => !i.IsDisabled);
                break;
            case "End":
                _highlighted = VisibleItems.LastOrDefault(i => !i.IsDisabled);
                break;
            case "Enter":
                // Select the anchored highlight only while it is still visible
                // under the current filter (never a positional fallback).
                var items = VisibleItems;
                if (_highlighted is not null && items.Contains(_highlighted))
                    await _highlighted.SelectAsync();
                break;
        }
    }

    // Wrapping step that skips disabled items; bails out after one full lap so
    // a list of only-disabled items cannot loop forever.
    private void MoveHighlight(int direction)
    {
        var items = VisibleItems;
        if (items.Count == 0)
        {
            _highlighted = null;
            return;
        }

        // Derive the starting ordinal from the anchored item each move so an
        // insertion/removal around it doesn't desync the step. A highlight that
        // is no longer visible (filtered or unmounted) restarts from the edge.
        var idx = _highlighted is not null ? items.IndexOf(_highlighted) : -1;
        for (var step = 0; step < items.Count; step++)
        {
            idx = direction > 0
                ? (idx + 1) % items.Count
                : idx <= 0 ? items.Count - 1 : idx - 1;
            if (!items[idx].IsDisabled)
            {
                _highlighted = items[idx];
                return;
            }
        }
        _highlighted = null;
    }

    /// <summary>The element id of the currently highlighted item, or null when
    /// nothing is highlighted. Drives both <c>aria-activedescendant</c> on the
    /// input and the scroll-into-view target.</summary>
    private string? HighlightedItemId
        => _highlighted is not null && VisibleItems.Contains(_highlighted)
            ? _highlighted.ItemId
            : null;

    // Keep the highlighted item visible as the keyboard moves it past the
    // scroll viewport edge (#214). Only scrolls when the target changes so an
    // unrelated re-render doesn't fight the user's mouse-wheel scroll.
    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        var id = HighlightedItemId;
        if (id is null)
        {
            _lastScrolledItemId = null;
            return;
        }
        if (id == _lastScrolledItemId) return;
        _lastScrolledItemId = id;
        // Guard the interop against a disconnect/disposal race so a late
        // OnAfterRender during teardown can't throw and destabilize rendering;
        // reset the tracker so a live re-render can retry the scroll.
        try
        {
            await Interop.ScrollIntoView(id, "nearest");
        }
        catch (JSDisconnectedException) { _lastScrolledItemId = null; }
        catch (ObjectDisposedException) { _lastScrolledItemId = null; }
        catch (InvalidOperationException) { _lastScrolledItemId = null; } // JS unavailable during prerender
    }

    public record CommandContext(
        string SearchText,
        EventCallback<string> OnSearch,
        EventCallback<KeyboardEventArgs> OnNavigationKey,
        int VisibleItemCount,
        string ListId,
        string? HighlightedItemId,
        Command Owner);
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@* Only renders when every CommandItem has been filtered out — previously rendered unconditionally so users
   saw the empty text stacked under their matching items. *@
@if (IsVisible)
{
    <div class="@CssClass" @attributes="AdditionalAttributes">
        @if (ChildContent is not null)
        {
            @ChildContent
        }
        else
        {
            <span>@L["Command.NoResults"]</span>
        }
    </div>
}

@code {
    [CascadingParameter] public Command.CommandContext? Context { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool IsVisible => Context is null || Context.VisibleItemCount == 0;

    private string CssClass => Cx.Merge("py-6 text-center text-sm text-muted-foreground", Class);
}

@namespace Lumeo

@* The group hides itself (heading included) when every one of its CommandItems
   is filtered out — cmdk parity. CSS-hidden via the native [hidden] attribute
   instead of unmounting, so the items stay registered with the Command and the
   group reappears the moment the filter matches again. *@
<div class="@CssClass" hidden="@(!HasVisibleItems)" @attributes="AdditionalAttributes">
    @if (Heading is not null)
    {
        <div class="px-2 py-1.5 text-xs font-medium text-muted-foreground">@Heading</div>
    }
    <CascadingValue Value="this" IsFixed="true">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [CascadingParameter] public Command.CommandContext? Context { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Heading { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly List<CommandItem> _items = new();

    private string CssClass => Cx.Merge("overflow-hidden p-1 text-foreground", Class);

    // An empty registry means the group hosts arbitrary (non-item) content —
    // never hide those.
    private bool HasVisibleItems => _items.Count == 0
        || Context is null
        || _items.Any(i => Command.MatchesFilter(Context.SearchText, i.ItemFilterValue));

    // Items register idempotently per instance (OnParametersSet can run twice
    // per parent render) and unregister on Dispose. No StateHasChanged here:
    // everything that affects visibility (search text, item add/remove, a
    // FilterValue change) already re-renders the Command tree through its
    // cascading context, which re-renders this group with a fresh registry.
    internal void RegisterItem(CommandItem item)
    {
        if (!_items.Contains(item)) _items.Add(item);
    }

    internal void UnregisterItem(CommandItem item) => _items.Remove(item);
}

@namespace Lumeo
@implements IAsyncDisposable
@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@* Mirror every other Command sub-part: a misplaced input (rendered outside a
   Command, or before the cascade resolves) must not crash the tree, so the
   markup only renders once the cascading Context is present. *@
@if (Context is not null)
{
    <div class="flex items-center border-b border-border/40 px-3">
        <SvgGlyph Svg="@(LumeoIcons.Search)" class="me-2 h-4 w-4 shrink-0 opacity-50" />
        <input type="text"
               id="@_inputId"
               role="combobox"
               aria-expanded="true"
               aria-autocomplete="list"
               aria-controls="@Context.ListId"
               aria-activedescendant="@Context.HighlightedItemId"
               class="@CssClass"
               placeholder="@(Placeholder ?? L["Command.Placeholder"])"
               value="@Context.SearchText"
               @oninput="HandleInput"
               @onkeydown="HandleKeyDown"
               @attributes="AdditionalAttributes" />
    </div>
}

@code {
    [CascadingParameter] public Command.CommandContext? Context { get; set; }
    [Parameter] public string? Placeholder { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _inputId = LumeoIds.New("cmd-input");
    // Register against the id the DOM actually gets — a consumer `id` in the
    // splat overrides the generated one (Codex P2).
    private string EffectiveInputId => LumeoIds.Effective(AdditionalAttributes, _inputId);
    private string? _registeredId;

    private string CssClass => Cx.Merge("flex h-10 w-full rounded-md bg-transparent py-3 text-sm outline-none placeholder:text-muted-foreground disabled:cursor-not-allowed disabled:opacity-50", Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        try
        {
            // Key-selective preventDefault in JS (TabsTrigger pattern): the
            // arrows drive the highlight and must not move the caret, and a
            // bare Enter must not submit an enclosing form. Every rule skips
            // IME composition so candidate-list navigation / confirm keep
            // their defaults.
            _registeredId = EffectiveInputId;
            await Interop.RegisterPreventDefaultKeys(_registeredId, new[]
            {
                new PreventDefaultKeyRule("ArrowDown", SkipComposing: true),
                new PreventDefaultKeyRule("ArrowUp", SkipComposing: true),
                new PreventDefaultKeyRule("Enter", RequireNoModifiers: true, SkipComposing: true),
            });
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    private bool _pdRegistered;

    private async Task HandleInput(ChangeEventArgs e)
    {
        if (Context is null) return;
        await Context.OnSearch.InvokeAsync(e.Value?.ToString() ?? "");
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (Context is null) return;
        if (e.Key is "ArrowDown" or "ArrowUp" or "Home" or "End" or "Enter")
            await Context.OnNavigationKey.InvokeAsync(e);
    }

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered || _registeredId is null) return;
        try { await Interop.UnregisterPreventDefaultKeys(_registeredId); }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}

@namespace Lumeo
@implements IDisposable

@if (IsVisible)
{
    <button type="button"
            id="@_itemId"
            role="option"
            aria-selected="@(IsHighlighted ? "true" : "false")"
            aria-disabled="@(Disabled ? "true" : "false")"
            disabled="@Disabled"
            class="@CssClass"
            @onclick="HandleSelect"
            @attributes="AdditionalAttributes">
        @ChildContent
        @if (Shortcut is not null)
        {
            <span class="ms-auto flex items-center gap-0.5">
                @foreach (var part in Shortcut.Split('+'))
                {
                    <Kbd>@part.Trim()</Kbd>
                }
            </span>
        }
    </button>
}

@code {
    [CascadingParameter] public Command.CommandContext? Context { get; set; }
    // Present when the item sits inside a CommandGroup (nearest group wins) so
    // the group can hide itself when all of its items are filtered out.
    [CascadingParameter] public CommandGroup? Group { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public EventCallback OnSelect { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Shortcut { get; set; }
    [Parameter] public string? FilterValue { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _itemId = LumeoIds.New("cmd-item");
    private bool _registered;
    private bool _groupRegistered;
    private string? _lastFilterValue;
    private bool _lastDisabled;

    // Read by Command (nav list, highlight skip, visible count) and
    // CommandGroup (hide-when-empty) through the registration.
    internal string ItemId => _itemId;
    internal bool IsDisabled => Disabled;
    internal string? ItemFilterValue => FilterValue;
    internal Task SelectAsync() => HandleSelect();

    private bool IsVisible => Context is null || Command.MatchesFilter(Context.SearchText, FilterValue);

    private bool IsHighlighted => Context?.HighlightedItemId == _itemId;

    private string CssClass => Cx.Merge(
        "relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground disabled:pointer-events-none disabled:opacity-50",
        Cx.When(IsHighlighted && !Disabled, "bg-accent text-accent-foreground"),
        Class);

    protected override void OnParametersSet()
    {
        // Register once per mounted instance, idempotently keyed on the component
        // (OnParametersSet can run twice per parent render via cascading-value
        // double notification). Visibility no longer drives register/unregister
        // churn — Command applies the filter at read time, which keeps the
        // keyboard-nav list in DOM order across filter round-trips.
        var wasRegistered = _registered;
        if (!_registered && Context is not null)
        {
            Context.Owner.RegisterItem(this);
            _registered = true;
        }
        if (!_groupRegistered && Group is not null)
        {
            Group.RegisterItem(this);
            _groupRegistered = true;
        }

        // Filter/disabled parameters changed after registration — the owner's
        // visible count, group hiding and highlight skipping depend on them.
        if (wasRegistered && (_lastFilterValue != FilterValue || _lastDisabled != Disabled))
            Context?.Owner.NotifyItemChanged();
        _lastFilterValue = FilterValue;
        _lastDisabled = Disabled;
    }

    public void Dispose()
    {
        // Ownership guard: registrations are keyed on the instance itself, so
        // this can only ever remove this component's own entry.
        if (_registered) Context?.Owner.UnregisterItem(this);
        if (_groupRegistered) Group?.UnregisterItem(this);
    }

    private async Task HandleSelect()
    {
        if (Disabled) return;
        await OnSelect.InvokeAsync();
    }
}

